<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Ubuntu Desktop Clone</title>
    <style>
        :root {
            --ubuntu-orange: #E95420;
            --ubuntu-purple: #300a24;
            --ubuntu-dark-purple: #2c061f;
            --ubuntu-bar: rgba(0, 0, 0, 0.6);
            --window-bg: #f2f2f2;
            --text-color: #333;
        }

        * { box-sizing: border-box; margin: 0; padding: 0; user-select: none; }

        body, html {
            width: 100%;
            height: 100%;
            overflow: hidden;
            font-family: 'Ubuntu', sans-serif, Arial;
        }

        #desktop {
            width: 100vw;
            height: 100vh;
            background: linear-gradient(135deg, #300a24 0%, #772953 100%);
            position: relative;
            overflow: hidden;
        }

        /* Taskbar/Dock */
        #taskbar {
            position: absolute;
            bottom: 10px;
            left: 50%;
            transform: translateX(-50%);
            background: var(--ubuntu-bar);
            backdrop-filter: blur(10px);
            padding: 8px 15px;
            border-radius: 20px;
            display: flex;
            gap: 15px;
            align-items: center;
            z-index: 1000;
            border: 1px solid rgba(255,255,255,0.1);
        }

        .launcher-btn {
            width: 40px;
            height: 40px;
            background: rgba(255,255,255,0.1);
            border-radius: 8px;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            transition: background 0.2s;
            font-size: 24px;
        }

        .launcher-btn:hover {
            background: rgba(255,255,255,0.2);
        }

        /* Window Styles */
        .window {
            position: absolute;
            min-width: 360px;
            min-height: 240px;
            background: var(--window-bg);
            border-radius: 8px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
            display: none;
            flex-direction: column;
            overflow: hidden;
            z-index: 10;
        }

        .win-header {
            background: #e9e9e9;
            padding: 8px 12px;
            display: flex;
            align-items: center;
            justify-content: space-between;
            cursor: move;
            border-bottom: 1px solid #ccc;
        }

        .win-controls {
            display: flex;
            gap: 8px;
        }

        .win-close {
            width: 14px;
            height: 14px;
            background: #ff5f56;
            border-radius: 50%;
            cursor: pointer;
            border: none;
        }

        .win-content {
            flex: 1;
            padding: 10px;
            overflow: auto;
            color: var(--text-color);
        }

        /* Files App Styles */
        #files-path {
            font-family: monospace;
            background: #eee;
            padding: 4px 8px;
            margin-bottom: 10px;
            border-radius: 4px;
            font-size: 0.9em;
        }

        #files-up {
            cursor: pointer;
            background: #ddd;
            border: none;
            padding: 2px 8px;
            margin-right: 10px;
            border-radius: 3px;
            font-size: 0.8em;
        }

        #files-up:hover { background: #ccc; }

        .fs-list {
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(80px, 1fr));
            gap: 15px;
        }

        .fs-item {
            display: flex;
            flex-direction: column;
            align-items: center;
            text-align: center;
            cursor: pointer;
            font-size: 0.85em;
            padding: 5px;
            border-radius: 4px;
        }

        .fs-item:hover { background: rgba(0,0,0,0.05); }

        .fs-icon {
            font-size: 32px;
            margin-bottom: 5px;
        }

        /* Notepad Styles */
        #tabs {
            display: flex;
            background: #ddd;
            padding: 5px 5px 0 5px;
            gap: 2px;
            align-items: flex-end;
        }

        .tab {
            padding: 6px 12px;
            background: #bbb;
            border-radius: 5px 5px 0 0;
            cursor: pointer;
            font-size: 0.85em;
            max-width: 120px;
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
        }

        .tab.active {
            background: var(--window-bg);
        }

        #new-tab {
            padding: 4px 8px;
            cursor: pointer;
            font-weight: bold;
            border: none;
            background: transparent;
            font-size: 1.2em;
        }

        #editor {
            width: 100%;
            height: 100%;
            min-height: 200px;
            border: none;
            resize: none;
            padding: 10px;
            font-family: monospace;
            outline: none;
            background: transparent;
        }

    </style>
</head>
<body>

<div id="desktop">
    <!-- Taskbar -->
    <div id="taskbar">
        <div class="launcher-btn" id="open-files" title="Files">📁</div>
        <div class="launcher-btn" id="open-notepad" title="Notepad">📝</div>
    </div>

    <!-- Files Window -->
    <div id="files-window" class="window">
        <div class="win-header">
            <div style="display: flex; align-items: center;">
                <button id="files-up">UP</button>
                <span id="files-path">/</span>
            </div>
            <div class="win-controls">
                <button class="win-close"></button>
            </div>
        </div>
        <div class="win-content">
            <div id="fs-container" class="fs-list"></div>
        </div>
    </div>

    <!-- Notepad Window -->
    <div id="notepad-window" class="window">
        <div class="win-header">
            <span>Notepad</span>
            <div class="win-controls">
                <button class="win-close"></button>
            </div>
        </div>
        <div id="tabs">
            <!-- Tabs injected here -->
            <button id="new-tab">+</button>
        </div>
        <div class="win-content" style="padding: 0; display: flex; flex-direction: column;">
            <textarea id="editor"></textarea>
        </div>
    </div>
</div>

<script>
    /** --- Filesystem Logic --- **/
    const fsData = {
        'bin': {},
        'etc': {},
        'home': {
            'user': {
                'Documents': { 'resume.txt': null, 'budget.xlsx': null },
                'Downloads': { 'ubuntu-iso.iso': null },
                'Pictures': { 'wallpaper.png': null }
            }
        },
        'usr': {},
        'var': {}
    };

    let currentPath = []; // Array of keys representing path from root

    function getDirAt(pathArr) {
        let current = fsData;
        for (const part of pathArr) {
            if (current[part] === undefined) return null;
            current = current[part];
        }
        return current;
    }

    function renderFiles() {
        const container = document.getElementById('fs-container');
        const pathDisplay = document.getElementById('files-path');
        const dir = getDirAt(currentPath);

        pathDisplay.innerText = '/' + currentPath.join('/');
        container.innerHTML = '';

        if (!dir) return;

        Object.keys(dir).forEach(key => {
            const isFolder = typeof dir[key] === 'object' && dir[key] !== null;
            const item = document.createElement('div');
            item.className = 'fs-item';

            const icon = document.createElement('div');
            icon.className = 'fs-icon';
            icon.innerText = isFolder ? '📁' : '📄';

            const label = document.createElement('div');
            label.innerText = key;

            item.appendChild(icon);
            item.appendChild(label);

            item.addEventListener('dblclick', () => {
                if (isFolder) {
                    currentPath.push(key);
                    renderFiles();
                }
            });

            container.appendChild(item);
        });
    }

    document.getElementById('files-up').addEventListener('click', () => {
        if (currentPath.length > 0) {
            currentPath.pop();
            renderFiles();
        }
    });

    /** --- Notepad Logic --- **/
    let notepadState = {
        tabs: [{ id: Date.now(), title: 'Untitled', content: '' }],
        activeTabId: null
    };

    // Load from localStorage
    const saved = localStorage.getItem('notepad_persistence');
    if (saved) {
        try {
            const parsed = JSON.parse(saved);
            notepadState.tabs = parsed.tabs;
            notepadState.activeTabId = parsed.activeTabId;
        } catch(e) { console.error("Failed to load notepad", e); }
    } else {
        notepadState.activeTabId = notepadState.tabs[0].id;
    }

    const editor = document.getElementById('editor');
    const tabsContainer = document.getElementById('tabs');
    const newTabBtn = document.getElementById('new-tab');

    function saveNotepad() {
        localStorage.setItem('notepad_persistence', JSON.stringify(notepadState));
    }

    function renderTabs() {
        // Clear existing tabs (keep the + button)
        const buttons = tabsContainer.querySelectorAll('.tab');
        buttons.forEach(b => b.remove());

        notepadState.tabs.forEach(tab => {
            const tabEl = document.createElement('div');
            tabEl.className = 'tab' + (tab.id === notepadState.activeTabId ? ' active' : '');
            tabEl.innerText = tab.title || 'Untitled';
            tabEl.addEventListener('click', () => switchTab(tab.id));
            tabsContainer.insertBefore(tabEl, newTabBtn);
        });

        const activeTab = notepadState.tabs.find(t => t.id === notepadState.activeTabId);
        editor.value = activeTab ? activeTab.content : '';
    }

    function switchTab(id) {
        notepadState.activeTabId = id;
        renderTabs();
        saveNotepad();
    }

    newTabBtn.addEventListener('click', () => {
        const newId = Date.now();
        notepadState.tabs.push({ id: newId, title: 'Untitled', content: '' });
        notepadState.activeTabId = newId;
        renderTabs();
        saveNotepad();
    });

    editor.addEventListener('input', (e) => {
        const activeTab = notepadState.tabs.find(t => t.id === notepadState.activeTabId);
        if (activeTab) {
            activeTab.content = e.target.value;
            // Update title if content exists
            if (activeTab.content.length > 0 && activeTab.title === 'Untitled') {
                activeTab.title = activeTab.content.substring(0, 10).replace(/\n/g, '') + '...';
            }
            saveNotepad();
            // We don't re-render tabs on every keystroke to avoid losing cursor position, 
            // but we update the title logic via a debounced or simple check if needed.
            // For this requirement, just saving content is enough.
        }
    });

    /** --- Window Management --- **/
    function setupWindow(winId) {
        const win = document.getElementById(winId);
        const header = win.querySelector('.win-header');
        const closeBtn = win.querySelector('.win-close');

        // Close functionality
        closeBtn.addEventListener('click', () => {
            win.style.display = 'none';
        });

        // Bring to front on click
        win.addEventListener('mousedown', () => {
            document.querySelectorAll('.window').forEach(w => w.style.zIndex = 10);
            win.style.zIndex = 100;
        });

        // Dragging logic
        let isDragging = false;
        let offsetX, offsetY;

        header.addEventListener('mousedown', (e) => {
            isDragging = true;
            offsetX = e.clientX - win.offsetLeft;
            offsetY = e.clientY - win.offsetTop;
            e.preventDefault();
        });

        document.addEventListener('mousemove', (e) => {
            if (!isDragging) return;
            win.style.left = (e.clientX - offsetX) + 'px';
            win.style.top = (e.clientY - offsetY) + 'px';
        });

        document.addEventListener('mouseup', () => {
            isDragging = false;
        });
    }

    // Launchers
    document.getElementById('open-files').addEventListener('click', () => {
        const win = document.getElementById('files-window');
        win.style.display = 'flex';
        win.style.left = '50px';
        win.style.top = '50px';
    });

    document.getElementById('open-notepad').addEventListener('click', () => {
        const win = document.getElementById('notepad-window');
        win.style.display = 'flex';
        win.style.left = '100px';
        win.style.top = '100px';
    });

    // Init
    renderFiles();
    renderTabs();
    setupWindow('files-window');
    setupWindow('notepad-window');

</script>
</body>
</html>
